from enum import Enum, auto
from dataclasses import dataclass, field

class DataClass(str, Enum):
    PUBLIC       = "public"        # no restrictions
    INTERNAL     = "internal"      # company-internal, non-sensitive
    CONFIDENTIAL = "confidential"  # business-sensitive, limited access
    RESTRICTED   = "restricted"    # PII, health, financial — tightly controlled

class DataCategory(str, Enum):
    GENERAL     = "general"
    PII         = "pii"           # GDPR personal data
    HEALTH      = "health"        # HIPAA PHI
    FINANCIAL   = "financial"     # PCI-DSS
    LEGAL       = "legal"         # attorney-client privilege
    CREDENTIALS = "credentials"   # API keys, passwords

@dataclass
class DataRecord:
    content: str
    data_class: DataClass
    categories: list[DataCategory]
    owner_id: str          # user or tenant who owns this data
    purpose: str           # stated processing purpose
    consent_ref: str       # ID of consent record (empty if not required)
    provenance: str        # where the data originated
    created_at: str        # ISO-8601
    retention_days: int    # 0 = session-only, -1 = indefinite (must be justified)
    tags: list[str] = field(default_factory=list)

# Controls derived from classification
CONTROLS: dict[DataClass, dict] = {
    DataClass.PUBLIC: {
        "can_log": True, "can_cache": True, "encryption_required": False,
        "third_party_llm_allowed": True, "retention_days_max": 365,
    },
    DataClass.INTERNAL: {
        "can_log": True, "can_cache": True, "encryption_required": True,
        "third_party_llm_allowed": True, "retention_days_max": 90,
    },
    DataClass.CONFIDENTIAL: {
        "can_log": True, "can_cache": False, "encryption_required": True,
        "third_party_llm_allowed": True, "retention_days_max": 30,
    },
    DataClass.RESTRICTED: {
        "can_log": False, "can_cache": False, "encryption_required": True,
        "third_party_llm_allowed": False, "retention_days_max": 7,
    },
}

def get_controls(record: DataRecord) -> dict:
    return CONTROLS[record.data_class]

from dataclasses import dataclass
from datetime import datetime

@dataclass
class ConsentRecord:
    consent_id: str
    user_id: str
    purposes: list[str]       # e.g. ["chat_completion", "abuse_monitoring"]
    granted_at: str
    expires_at: str | None    # None = indefinite (requires justification)
    withdrawn_at: str | None  # set on withdrawal

    @property
    def is_active(self) -> bool:
        if self.withdrawn_at:
            return False
        if self.expires_at:
            return datetime.fromisoformat(self.expires_at) > datetime.utcnow()
        return True

    def allows(self, purpose: str) -> bool:
        return self.is_active and purpose in self.purposes

# Consent store (in production: database)
_consent_store: dict[str, ConsentRecord] = {}

def check_purpose_allowed(user_id: str, purpose: str) -> bool:
    """Return True only if an active consent record covers this purpose."""
    record = _consent_store.get(user_id)
    if record is None:
        return False
    return record.allows(purpose)

def withdraw_consent(user_id: str) -> None:
    """Mark consent withdrawn — triggers data deletion pipeline."""
    if user_id in _consent_store:
        _consent_store[user_id].withdrawn_at = datetime.utcnow().isoformat()
    # In production: enqueue deletion job for all data associated with user_id

import uuid
from dataclasses import dataclass, field

@dataclass
class LineageNode:
    node_id: str
    node_type: str          # "user_input" | "llm_call" | "rag_retrieval" | "tool_output"
    content_hash: str       # SHA-256 of content (not plaintext)
    data_class: DataClass
    categories: list[DataCategory]
    owner_ids: list[str]    # user/tenant IDs whose data is involved
    parent_ids: list[str]   # IDs of upstream nodes this node depends on
    timestamp: str

_lineage: dict[str, LineageNode] = {}

def record_lineage(node: LineageNode) -> None:
    _lineage[node.node_id] = node

def trace_owner(owner_id: str) -> list[LineageNode]:
    """Return all lineage nodes associated with a given owner."""
    return [n for n in _lineage.values() if owner_id in n.owner_ids]

def erasure_impact(owner_id: str) -> set[str]:
    """
    Return all node IDs that must be invalidated/deleted when
    owner_id exercises right-to-erasure.
    """
    affected = {n.node_id for n in trace_owner(owner_id)}
    # Also include nodes that depend on affected nodes (downstream)
    changed = True
    while changed:
        changed = False
        for node in _lineage.values():
            if node.node_id not in affected:
                if any(p in affected for p in node.parent_ids):
                    affected.add(node.node_id)
                    changed = True
    return affected
